postgres.code:
-- Basic database creation
CREATE DATABASE sampledb;

-- Database with template and encoding
CREATE DATABASE sampledb_custom
WITH TEMPLATE template1
     ENCODING 'UTF8'
     LC_COLLATE 'en_US.UTF-8'
     LC_CTYPE 'en_US.UTF-8';

-- Database with specific owner
CREATE DATABASE sampledb_owned
WITH OWNER = myuser
     ENCODING = 'UTF8';

-- Database from template
CREATE DATABASE test_db
WITH TEMPLATE production_db;

-- List available templates
SELECT datname FROM pg_database WHERE datistemplate = true;

-- Drop database
DROP DATABASE sampledb;

sqlServer.code:
-- Database-level options
ALTER DATABASE SampleDB SET RECOVERY FULL;
ALTER DATABASE SampleDB SET AUTO_SHRINK OFF;
ALTER DATABASE SampleDB SET AUTO_CLOSE OFF;
ALTER DATABASE SampleDB SET PAGE_VERIFY CHECKSUM;

-- Server-level configuration
EXEC sp_configure 'max server memory (MB)', 4096;
RECONFIGURE;

-- View database options
SELECT name, collation_name, is_auto_close_on,
       is_auto_shrink_on, page_verify_option_desc
FROM sys.databases
WHERE name = 'SampleDB';

-- View server configuration
SELECT name, value, description
FROM sys.configurations
WHERE name LIKE '%memory%';

postgres.code:
-- Database-level settings
ALTER DATABASE sampledb SET work_mem = '64MB';
ALTER DATABASE sampledb SET maintenance_work_mem = '256MB';
ALTER DATABASE sampledb SET default_statistics_target = 1000;

-- Session-level settings
SET work_mem = '128MB';
SET enable_seqscan = off;

-- View current settings
SHOW work_mem;
SHOW ALL;

-- Configuration file locations
SHOW config_file;
SHOW hba_file;
SHOW data_directory;

-- View database-specific settings
SELECT datname, setconfig
FROM pg_db_role_setting drs
LEFT JOIN pg_database d ON d.oid = drs.setdatabase
WHERE datname = 'sampledb';

-- Reload configuration
SELECT pg_reload_conf();
